// sv_phys.ts
let sv_time = 0;
let host_frametime = 0;

// All functions are 'static' members of a namespace-class — looks like module style but is not
class sv {
  static checkAllEnts(): void {
    for (let e = 1; e < sv_numEdicts; e++) {
      const ent = getEdict(e);
      if (ent.free) continue;
      if (sv.testEntityPosition(ent))
        console.log('entity in invalid position');
    }
  }

  static testEntityPosition(ent: Edict): boolean {
    return svMove(ent.v.origin, ent.v.mins, ent.v.maxs, ent.v.origin, MOVE_NOMONSTERS, ent).startSolid;
  }
}
